import{_ as t,o as a,c as n,a2 as r}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Multi-Agent Systems for Coding Agents","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/multi-agent-systems/index.md","filePath":"research/concepts/multi-agent-systems/index.md"}'),o={name:"research/concepts/multi-agent-systems/index.md"};function s(i,e,l,d,c,h){return a(),n("div",null,[...e[0]||(e[0]=[r(`<h1 id="multi-agent-systems-for-coding-agents" tabindex="-1">Multi-Agent Systems for Coding Agents <a class="header-anchor" href="#multi-agent-systems-for-coding-agents" aria-label="Permalink to &quot;Multi-Agent Systems for Coding Agents&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Multi-agent systems (MAS) represent one of the most significant architectural patterns emerging in AI-powered software engineering. Rather than relying on a single monolithic agent to handle every aspect of code generation, analysis, and modification, multi-agent architectures decompose complex coding tasks across multiple specialized agents — each with distinct capabilities, context windows, and permission boundaries.</p><p>This research folder provides a comprehensive analysis of multi-agent patterns as they apply specifically to <strong>coding agents</strong> — AI systems that read, write, debug, and reason about source code. We draw from real-world implementations (ForgeCode, SageAgent, Claude Code, OpenHands, Codex CLI, Capy, TongAgents, Junie CLI) as well as foundational frameworks (OpenAI Swarm/Agents SDK, Google A2A Protocol, Anthropic&#39;s agentic patterns).</p><hr><h2 id="why-multi-agent-for-coding" tabindex="-1">Why Multi-Agent for Coding? <a class="header-anchor" href="#why-multi-agent-for-coding" aria-label="Permalink to &quot;Why Multi-Agent for Coding?&quot;">​</a></h2><p>Software engineering is inherently a multi-role discipline. Even a single developer switches between roles throughout the day:</p><ul><li><strong>Researcher</strong>: Understanding existing code, tracing dependencies, reading docs</li><li><strong>Architect</strong>: Planning changes, considering system-wide implications</li><li><strong>Implementer</strong>: Writing code, making modifications</li><li><strong>Reviewer</strong>: Checking work for correctness, style, edge cases</li><li><strong>Tester</strong>: Verifying that changes work as intended</li></ul><p>Multi-agent systems formalize this natural division. Instead of asking one LLM to simultaneously plan, implement, and verify — which strains context windows, creates conflicting objectives, and makes it hard to enforce quality gates — dedicated agents handle each phase with purpose-built prompts, tools, and constraints.</p><h3 id="the-core-tension" tabindex="-1">The Core Tension <a class="header-anchor" href="#the-core-tension" aria-label="Permalink to &quot;The Core Tension&quot;">​</a></h3><p>Multi-agent systems introduce complexity. Every agent boundary creates:</p><ol><li><strong>Communication overhead</strong> — Agents must share context, and information is lost at boundaries</li><li><strong>Coordination costs</strong> — Someone (or something) must decide which agent runs when</li><li><strong>Latency</strong> — Multiple LLM calls take more time than one</li><li><strong>Cost</strong> — More API calls means more tokens consumed</li></ol><p>The question is never &quot;should we use multi-agent?&quot; but rather &quot;does the task complexity justify the coordination overhead?&quot; For simple file edits, a single agent suffices. For multi-file refactors requiring planning, implementation, and verification — multi-agent architectures consistently outperform monolithic approaches.</p><hr><h2 id="key-patterns" tabindex="-1">Key Patterns <a class="header-anchor" href="#key-patterns" aria-label="Permalink to &quot;Key Patterns&quot;">​</a></h2><p>This folder explores the following multi-agent patterns in depth:</p><h3 id="architecture-patterns" tabindex="-1">Architecture Patterns <a class="header-anchor" href="#architecture-patterns" aria-label="Permalink to &quot;Architecture Patterns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Pattern</th><th>Key Insight</th></tr></thead><tbody><tr><td><a href="./orchestrator-worker.html">orchestrator-worker.md</a></td><td>Orchestrator-Worker</td><td>Central brain delegates; Anthropic&#39;s most-recommended pattern for coding</td></tr><tr><td><a href="./peer-to-peer.html">peer-to-peer.md</a></td><td>Peer-to-Peer</td><td>Agents as equals; debate, review, and consensus patterns</td></tr><tr><td><a href="./specialist-agents.html">specialist-agents.md</a></td><td>Specialist Agents</td><td>Purpose-built roles with hard boundaries; ForgeCode&#39;s 3-agent model</td></tr><tr><td><a href="./swarm-patterns.html">swarm-patterns.md</a></td><td>Swarm Patterns</td><td>Lightweight handoffs; OpenAI&#39;s approach to agent coordination</td></tr></tbody></table><h3 id="mechanism-patterns" tabindex="-1">Mechanism Patterns <a class="header-anchor" href="#mechanism-patterns" aria-label="Permalink to &quot;Mechanism Patterns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Pattern</th><th>Key Insight</th></tr></thead><tbody><tr><td><a href="./communication-protocols.html">communication-protocols.md</a></td><td>Communication Protocols</td><td>How agents talk: shared state, message passing, A2A, MCP</td></tr><tr><td><a href="./context-sharing.html">context-sharing.md</a></td><td>Context Sharing</td><td>The hardest problem: passing knowledge without blowing context windows</td></tr><tr><td><a href="./evaluation-agent.html">evaluation-agent.md</a></td><td>Evaluator-Optimizer</td><td>Generator + evaluator loops; enforced verification patterns</td></tr></tbody></table><h3 id="analysis" tabindex="-1">Analysis <a class="header-anchor" href="#analysis" aria-label="Permalink to &quot;Analysis&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Pattern</th><th>Key Insight</th></tr></thead><tbody><tr><td><a href="./real-world-examples.html">real-world-examples.md</a></td><td>Real-World Examples</td><td>Deep dives into ForgeCode, SageAgent, Claude Code, OpenHands, and more</td></tr><tr><td><a href="./agent-comparison.html">agent-comparison.md</a></td><td>Multi vs Single Agent</td><td>When to use which; trade-off analysis</td></tr></tbody></table><hr><h2 id="the-multi-agent-spectrum" tabindex="-1">The Multi-Agent Spectrum <a class="header-anchor" href="#the-multi-agent-spectrum" aria-label="Permalink to &quot;The Multi-Agent Spectrum&quot;">​</a></h2><p>Not all multi-agent systems are created equal. Implementations fall on a spectrum:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Single Agent ──────────────────────────────────────────── Full Multi-Agent</span></span>
<span class="line"><span>     │                    │                    │                    │</span></span>
<span class="line"><span>  Monolithic         Sub-Agent            Pipeline           Specialized</span></span>
<span class="line"><span>   Loop             Delegation           Orchestration        Ensemble</span></span>
<span class="line"><span>     │                    │                    │                    │</span></span>
<span class="line"><span>  mini-SWE          Claude Code            SageAgent          ForgeCode</span></span>
<span class="line"><span>  Aider basic       OpenHands              Junie CLI          Capy</span></span>
<span class="line"><span>  OpenCode          Codex CLI              (5 agents)         (Captain/Build)</span></span>
<span class="line"><span>                    Goose                                     TongAgents</span></span></code></pre></div><h3 id="level-0-single-agent" tabindex="-1">Level 0: Single Agent <a class="header-anchor" href="#level-0-single-agent" aria-label="Permalink to &quot;Level 0: Single Agent&quot;">​</a></h3><p>One LLM, one loop, one context window. Tools extend capability but there&#39;s no delegation. Examples: mini-SWE-agent, basic Aider, OpenCode.</p><h3 id="level-1-sub-agent-delegation" tabindex="-1">Level 1: Sub-Agent Delegation <a class="header-anchor" href="#level-1-sub-agent-delegation" aria-label="Permalink to &quot;Level 1: Sub-Agent Delegation&quot;">​</a></h3><p>A primary agent spawns child agents for specific tasks. The children run in isolated context windows and return summaries. The parent remains in control. This is primarily a <strong>context management</strong> strategy. Examples: Claude Code (explore/plan/general sub-agents), OpenHands (AgentDelegateAction), Codex CLI (explorer/worker roles), Goose (summon).</p><h3 id="level-2-pipeline-orchestration" tabindex="-1">Level 2: Pipeline Orchestration <a class="header-anchor" href="#level-2-pipeline-orchestration" aria-label="Permalink to &quot;Level 2: Pipeline Orchestration&quot;">​</a></h3><p>Multiple agents execute in a defined sequence, each transforming the output of the previous. May include feedback loops. Examples: SageAgent (5-agent pipeline with ObservationAgent feedback), Junie CLI (Planner→Executor→Verifier).</p><h3 id="level-3-specialized-ensemble" tabindex="-1">Level 3: Specialized Ensemble <a class="header-anchor" href="#level-3-specialized-ensemble" aria-label="Permalink to &quot;Level 3: Specialized Ensemble&quot;">​</a></h3><p>Distinct agents with hard role boundaries and non-overlapping capabilities, coordinated by an orchestration layer. Each agent has purpose-built prompts, tools, and permissions. Examples: ForgeCode (Forge/Muse/Sage with read-write vs read-only boundaries), Capy (Captain/Build with no-code vs no-questions constraints).</p><hr><h2 id="key-findings-from-research" tabindex="-1">Key Findings from Research <a class="header-anchor" href="#key-findings-from-research" aria-label="Permalink to &quot;Key Findings from Research&quot;">​</a></h2><h3 id="_1-context-isolation-is-the-primary-motivation" tabindex="-1">1. Context Isolation is the Primary Motivation <a class="header-anchor" href="#_1-context-isolation-is-the-primary-motivation" aria-label="Permalink to &quot;1. Context Isolation is the Primary Motivation&quot;">​</a></h3><p>Across all implementations we studied, the #1 reason for adopting multi-agent architecture is <strong>context window management</strong>, not task specialization. Claude Code&#39;s documentation makes this explicit: sub-agents exist to keep the main context clean. ForgeCode&#39;s bounded context model ensures only summaries — not raw exploration data — flow between agents.</p><h3 id="_2-enforcement-beats-prompting" tabindex="-1">2. Enforcement Beats Prompting <a class="header-anchor" href="#_2-enforcement-beats-prompting" aria-label="Permalink to &quot;2. Enforcement Beats Prompting&quot;">​</a></h3><p>ForgeCode&#39;s programmatic verification enforcement (the agent literally cannot mark a task as complete without running verification) produced their &quot;biggest single improvement.&quot; Compare this to Claude Code&#39;s prompt-based approach where the agent <em>decides</em> whether to run tests. Dedicated evaluator agents (SageAgent&#39;s ObservationAgent) provide a middle ground between full programmatic enforcement and pure prompting.</p><h3 id="_3-hard-boundaries-create-better-outputs" tabindex="-1">3. Hard Boundaries Create Better Outputs <a class="header-anchor" href="#_3-hard-boundaries-create-better-outputs" aria-label="Permalink to &quot;3. Hard Boundaries Create Better Outputs&quot;">​</a></h3><p>The most effective multi-agent systems impose <strong>hard constraints</strong> on agent capabilities:</p><ul><li>ForgeCode: Muse (planner) literally cannot write code; Sage (researcher) is never user-facing</li><li>Capy: Captain cannot write code; Build cannot ask clarifying questions</li><li>Claude Code: Explore sub-agents get a cheaper, faster model (Haiku) and read-only tools</li></ul><p>These constraints aren&#39;t limitations — they&#39;re features. They prevent role confusion and force each agent to excel within its domain.</p><h3 id="_4-no-production-system-uses-peer-to-peer" tabindex="-1">4. No Production System Uses Peer-to-Peer <a class="header-anchor" href="#_4-no-production-system-uses-peer-to-peer" aria-label="Permalink to &quot;4. No Production System Uses Peer-to-Peer&quot;">​</a></h3><p>Every multi-agent coding system we studied uses hierarchical patterns (parent→child, pipeline, orchestrator→worker). No production system uses true peer-to-peer negotiation, voting, or consensus. This may change as the field matures, but currently the overhead of peer coordination exceeds its benefits for structured coding tasks.</p><h3 id="_5-communication-patterns-cluster-into-three-types" tabindex="-1">5. Communication Patterns Cluster into Three Types <a class="header-anchor" href="#_5-communication-patterns-cluster-into-three-types" aria-label="Permalink to &quot;5. Communication Patterns Cluster into Three Types&quot;">​</a></h3><ul><li><strong>Summary-based handoff</strong>: Agent A explores, summarizes, passes summary to Agent B (ForgeCode, Claude Code)</li><li><strong>Event stream/pub-sub</strong>: Centralized event bus connects all agents (OpenHands)</li><li><strong>Spec/document-based</strong>: Written specification is the interface between agents (Capy)</li></ul><hr><h2 id="industry-frameworks" tabindex="-1">Industry Frameworks <a class="header-anchor" href="#industry-frameworks" aria-label="Permalink to &quot;Industry Frameworks&quot;">​</a></h2><p>Several frameworks provide building blocks for multi-agent systems:</p><table tabindex="0"><thead><tr><th>Framework</th><th>Creator</th><th>Key Concept</th><th>Production Ready</th></tr></thead><tbody><tr><td><strong>Agents SDK</strong></td><td>OpenAI</td><td>Handoffs, guardrails, tracing</td><td>Yes</td></tr><tr><td><strong>Swarm</strong></td><td>OpenAI</td><td>Lightweight agent primitives (educational)</td><td>No (deprecated)</td></tr><tr><td><strong>A2A Protocol</strong></td><td>Google (Linux Foundation)</td><td>Agent-to-agent communication standard</td><td>Yes (v1.0)</td></tr><tr><td><strong>Claude Agent SDK</strong></td><td>Anthropic</td><td>Orchestrator-workers, evaluator-optimizer</td><td>Yes</td></tr><tr><td><strong>MCP</strong></td><td>Anthropic</td><td>Tool/context protocol (not agent-to-agent)</td><td>Yes</td></tr><tr><td><strong>LangGraph</strong></td><td>LangChain</td><td>Graph-based agent orchestration</td><td>Yes</td></tr><tr><td><strong>CrewAI</strong></td><td>CrewAI</td><td>Role-based multi-agent framework</td><td>Yes</td></tr><tr><td><strong>AutoGen</strong></td><td>Microsoft</td><td>Multi-agent conversation framework</td><td>Yes</td></tr></tbody></table><hr><h2 id="how-to-read-this-folder" tabindex="-1">How to Read This Folder <a class="header-anchor" href="#how-to-read-this-folder" aria-label="Permalink to &quot;How to Read This Folder&quot;">​</a></h2><p><strong>Start here</strong> if you&#39;re new to multi-agent systems:</p><ol><li>This README for overview</li><li><a href="./orchestrator-worker.html">orchestrator-worker.md</a> for the most common pattern</li><li><a href="./specialist-agents.html">specialist-agents.md</a> for role design</li><li><a href="./real-world-examples.html">real-world-examples.md</a> for concrete implementations</li></ol><p><strong>Deep dive</strong> into specific mechanisms:</p><ul><li><a href="./communication-protocols.html">communication-protocols.md</a> for how agents talk</li><li><a href="./context-sharing.html">context-sharing.md</a> for the hardest problem in multi-agent</li><li><a href="./evaluation-agent.html">evaluation-agent.md</a> for quality assurance patterns</li></ul><p><strong>Explore alternative patterns</strong>:</p><ul><li><a href="./peer-to-peer.html">peer-to-peer.md</a> for non-hierarchical approaches</li><li><a href="./swarm-patterns.html">swarm-patterns.md</a> for lightweight coordination</li><li><a href="./agent-comparison.html">agent-comparison.md</a> for the multi vs single agent decision</li></ul><hr><h2 id="terminology" tabindex="-1">Terminology <a class="header-anchor" href="#terminology" aria-label="Permalink to &quot;Terminology&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Agent</strong></td><td>An LLM with instructions, tools, and an execution loop</td></tr><tr><td><strong>Sub-agent</strong></td><td>A child agent spawned by a parent agent for a specific task</td></tr><tr><td><strong>Orchestrator</strong></td><td>A central agent that decomposes tasks and delegates to workers</td></tr><tr><td><strong>Worker</strong></td><td>An agent that executes a specific subtask assigned by an orchestrator</td></tr><tr><td><strong>Handoff</strong></td><td>The transfer of control from one agent to another</td></tr><tr><td><strong>Context window</strong></td><td>The maximum token capacity of an LLM&#39;s input</td></tr><tr><td><strong>Bounded context</strong></td><td>A pattern where only summaries (not raw data) cross agent boundaries</td></tr><tr><td><strong>Agent card</strong></td><td>A metadata document describing an agent&#39;s capabilities (A2A term)</td></tr><tr><td><strong>Specialist agent</strong></td><td>An agent designed for a single, well-defined role</td></tr><tr><td><strong>Agentic loop</strong></td><td>The core cycle: observe → think → act → observe</td></tr><tr><td><strong>Event stream</strong></td><td>A pub/sub message bus connecting agents (OpenHands pattern)</td></tr><tr><td><strong>Verification skill</strong></td><td>A programmatic check that runs before task completion</td></tr></tbody></table><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Anthropic. &quot;Building Effective Agents.&quot; 2024. <a href="https://www.anthropic.com/research/building-effective-agents" target="_blank" rel="noreferrer">https://www.anthropic.com/research/building-effective-agents</a></li><li>OpenAI. &quot;Swarm (experimental).&quot; 2024. <a href="https://github.com/openai/swarm" target="_blank" rel="noreferrer">https://github.com/openai/swarm</a></li><li>OpenAI. &quot;Agents SDK.&quot; 2025. <a href="https://github.com/openai/openai-agents-python" target="_blank" rel="noreferrer">https://github.com/openai/openai-agents-python</a></li><li>Google. &quot;Agent2Agent Protocol.&quot; 2025. <a href="https://github.com/a2aproject/A2A" target="_blank" rel="noreferrer">https://github.com/a2aproject/A2A</a></li><li>Anthropic. &quot;Model Context Protocol.&quot; 2024. <a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">https://modelcontextprotocol.io</a></li><li>Research files in <code>/research/agents/*/</code> — ForgeCode, SageAgent, Claude Code, OpenHands, TongAgents, Capy, Codex, Goose, Junie CLI</li></ul>`,66)])])}const m=t(o,[["render",s]]);export{p as __pageData,m as default};
